-- Generated from daggerheart.db after equipment import.

DROP TABLE IF EXISTS srd_equipement;

CREATE TABLE IF NOT EXISTS srd_equipment (
    equipment_id BIGSERIAL PRIMARY KEY,

    item_name TEXT,
    category TEXT, -- weapon, armor
    subcategory TEXT,

    tier INTEGER,
    trait TEXT,
    range TEXT,

    damage_text TEXT,
    damage_type TEXT,

    burden TEXT,
    thresholds_major TEXT,
    thresholds_severe TEXT,
    base_score INTEGER,

    feature_text TEXT,
    description_text TEXT,

    source_id TEXT REFERENCES srd_sources(id)
);

