(1038, 'REPLICATION PARCHMENT', 'Consumable', 'Consumable', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'By touching this piece of parchment to another, you can perfectly copy the second parchment''s contents. Once used, this parchment becomes mundane paper.', 'https://daggerheartsrd.com/consumables/replication-parchment/'),
