(1040, 'SLEEPING SAP', 'Consumable', 'Consumable', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'You can drink this potion to fall asleep for a full night''s rest. You clear all Stress upon waking.', 'https://daggerheartsrd.com/consumables/sleeping-sap/'),
(1041, 'SNAP POWDER', 'Consumable', 'Consumable', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Mark a Stress and clear a HP.', 'https://daggerheartsrd.com/consumables/snap-powder/'),
(1042, 'STAMINA POTION', 'Consumable', 'Consumable', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Clear 1d4+1 Stress.', 'https://daggerheartsrd.com/consumables/stamina-potion/'),
(1043, 'STARDROP', 'Consumable', 'Consumable', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'You can use this stardrop to summon a hailstorm of comets that deals 8d20 physical damage to all targets within Very Far range.', 'https://daggerheartsrd.com/consumables/stardrop/'),
