(1045, 'SUN TREE SAP', 'Consumable', 'Consumable', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Consume this sap to roll a d6. On a result of 5-6, clear 2 HP. On a result of 2-4, clear 3 Stress. On a result of 1, see through the veil of death and return unscathed, gaining one scar.', 'https://daggerheartsrd.com/consumables/sun-tree-sap/'),
(1046, 'SWEET MOSS', 'Consumable', 'Consumable', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'You can consume this moss during a rest to clear 1d10 HP or 1d10 Stress.', 'https://daggerheartsrd.com/consumables/sweet-moss/'),
(1047, 'UNSTABLE ARCANE SHARD', 'Consumable', 'Consumable', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'You can make a Finesse Roll to throw this shard at a group of adversaries within Far range. Targets you succeed against take 1d20 magic damage.', 'https://daggerheartsrd.com/consumables/unstable-arcane-shard/'),
(1048, 'VARIK LEAVES', 'Consumable', 'Consumable', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'You can eat these paired leaves to immediately gain 2 Hope.', 'https://daggerheartsrd.com/consumables/varik-leaves/'),
(1049, 'VIAL OF DARKSMOKE', 'Consumable', 'Consumable', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'When an adversary attacks you, use this vial and roll a number of d6 equal to your Agility. Add the highest result to your Evasion against the attack.', 'https://daggerheartsrd.com/consumables/vial-of-darksmoke/'),
