(932, 'AIRBLADE CHARM', 'Item', 'Item', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'You can attach this charm to a weapon with a Melee range. Three times per rest, you can activate the charm and attack a target within Close range.', 'https://daggerheartsrd.com/items/airblade-charm/'),
(933, 'ALISTAIR''S TORCH', 'Item', 'Item', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'You can light this magic torch at will. The flame''s light fills a much larger space than it should, enough to illuminate a cave bright as day.', 'https://daggerheartsrd.com/items/alistairs-torch/'),
