(945, 'CLAY COMPANION', 'Item', 'Item', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'When you sculpt this ball of clay into a clay animal companion, it behaves as that animal. For example, a clay spider can spin clay webs, while a clay bird can fly. The clay companion retains memory and identity across different shapes, but they can adopt new mannerisms with each form.', 'https://daggerheartsrd.com/items/clay-companion/'),
(946, 'COMPANION CASE', 'Item', 'Item', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'This case can fit a small animal companion. While the companion is inside, the animal and case are immune to all damage and harmful effects.', 'https://daggerheartsrd.com/items/companion-case/'),
(947, 'CONTROL RELIC', 'Item', 'Item', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'You gain a +1 bonus to your Finesse. You can only carry one relic.', 'https://daggerheartsrd.com/items/control-relic/'),
(948, 'CORRECTOR SPRITE', 'Item', 'Item', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'This tiny sprite sits in the curve of your ear canal and whispers helpful advice during combat. Once per short rest, you can gain advantage on an attack roll.', 'https://daggerheartsrd.com/items/corrector-sprite/'),
(949, 'DUAL FLASK', 'Item', 'Item', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'This flask can hold two different liquids. You can swap between them by flipping a small switch on the flask''s side.', 'https://daggerheartsrd.com/items/dual-flask/'),
(950, 'ELUSIVE AMULET', 'Item', 'Item', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Once per long rest, you can activate this amulet to become Hidden until you move. While Hidden in this way, you remain unseen even if an adversary moves to where they would normally see you.', 'https://daggerheartsrd.com/items/elusive-amulet/'),
(951, 'EMPTY CHEST', 'Item', 'Item', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'This magical chest appears empty. When you speak a specific trigger word or action and open the chest, you can see the items stored within it.', 'https://daggerheartsrd.com/items/empty-chest/'),
