(953, 'FIRE JAR', 'Item', 'Item', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'You can pour out the strange liquid contents of this jar to instantly produce fire. The contents regenerate when you take a long rest.', 'https://daggerheartsrd.com/items/fire-jar/'),
(954, 'FLICKERFLY PENDANT', 'Item', 'Item', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'While you carry this pendant, your weapons with a Melee range that deal physical damage have a gossamer sheen and can attack targets within Very Close range.', 'https://daggerheartsrd.com/items/flickerfly-pendant/'),
