(966, 'HONING RELIC', 'Item', 'Item', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'You gain a +1 bonus to an Experience of your choice. You can only carry one relic.', 'https://daggerheartsrd.com/items/honing-relic/'),
